export default async function translateText(text: string, countryCode: string): Promise<string> {
    try {
        const targetLang = countryToLanguage[countryCode] || 'en';
        const langTranslations = getTranslations(targetLang);
        if (langTranslations[text]) return langTranslations[text];

        if (typeof window !== 'undefined') {
            const cacheKey = `${targetLang}:${text}`;
            const cache = localStorage.getItem(CACHE_KEY);
            const cacheData = cache ? JSON.parse(cache) : {};
            if (cacheData[cacheKey]) return cacheData[cacheKey];

            try {
                const response = await axios.get('https://translate.googleapis.com/translate_a/single', {
                    params: { client: 'gtx', sl: 'en', tl: targetLang, dt: 't', q: text },
                    timeout: 5000,
                });
                const translated = response.data[0]?.map((item: unknown[]) => item[0]).filter(Boolean).join('') || text;
                cacheData[cacheKey] = translated;
                localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));
                return translated;
            } catch {
                return text;
            }
        }

        return text;
    } catch {
        return text;
    }
}